import type { PieceTexte } from '../pieceTextes';

const texte: PieceTexte = {
  source: 'Pierre Corneille, L\'Illusion comique (1635). Texte du domaine public. Source : texteslibres.fr.',
  blocs: [
    { k: 'acte', t: 'ACTE I' },
    { k: 'scene', t: 'Scène I' },
    { k: 'didascalie', t: '(PRIDAMANT, DORANTE.)' },
    { k: 'perso', t: 'DORANTE' },
    { k: 'ligne', t: 'Ce mage qui d\'un mot renverse la nature N\'a choisi pour palais que cette grotte obscure. La nuit qu\'il entretient sur cet affreux séjour N\'ouvrant son voile épais qu\'aux rayons d\'un faux jour, De leur éclat douteux n\'admet en ces lieux sombres Que ce qu\'en peut souffrir le commerce des ombres. N\'avancez pas : son art au pied de ce rocher A mis de quoi punir qui s\'en ose approcher ; Et cette large bouche est un mur invisible, Où l\'air en sa faveur devient inaccessible, Et lui fait un rempart, dont les funestes bords Sur un peu de poussière étalent mille morts. Jaloux de son repos plus que de sa défense, Il perd qui l\'importune, ainsi que qui l\'offense ; Malgré l\'empressement d\'un curieux désir, Il faut, pour lui parler, attendre son loisir : Chaque jour il se montre, et nous touchons à l\'heure Où, pour se divertir, il sort de sa demeure.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'J\'en attends peu de chose, et brûle de le voir. J\'ai de l\'impatience, et je manque d\'espoir. Ce fils, ce cher objet de mes inquiétudes, Qu\'ont éloigné de moi des traitements trop rudes, Et que depuis dix ans je cherche en tant de lieux, A caché pour jamais sa présence à mes yeux. Sous ombre qu\'il prenait un peu trop de licence, Contre ses libertés je roidis ma puissance ; Je croyais le dompter à force de punir, Et ma sévérité ne fit que le bannir. Mon âme vit l\'erreur dont elle était séduite : Je l\'outrageais présent, et je pleurai sa fuite ; Et l\'amour paternel me fit bientôt sentir D\'une injuste rigueur un juste repentir. Il l\'a fallu chercher : j\'ai vu dans mon voyage Le Pô, le Rhin, la Meuse, et la Seine, et le Tage : Toujours le même soin travaille mes esprits ; Et ces longues erreurs ne m\'en ont rien appris. Enfin, au désespoir de perdre tant de peine, Et n\'attendant plus rien de la prudence humaine, Pour trouver quelque borne à tant de maux soufferts, J\'ai déjà sur ce point consulté les enfers ; J\'ai vu les plus fameux en la haute science Dont vous dites qu\'Alcandre a tant d\'expérience : On m\'en faisait l\'état que vous faites de lui, Et pas un d\'eux n\'a pu soulager mon ennui. L\'enfer devient muet quand il me faut répondre, Ou ne me répond rien qu\'afin de me confondre.' },
    { k: 'perso', t: 'DORANTE' },
    { k: 'ligne', t: 'Ne traitez pas Alcandre en homme du commun, Ce qu\'il sait en son art n\'est connu de pas un. Je ne vous dirai point qu\'il commande au tonnerre, Qu\'il fait enfler les mers, qu\'il fait trembler la terre ; Que de l\'air, qu\'il mutine en mille tourbillons, Contre ses ennemis il fait des bataillons ; Que de ses mots savants les forces inconnues Transportent les rochers, font descendre les nues, Et briller dans la nuit l\'éclat de deux soleils ; Vous n\'avez pas besoin de miracles pareils : Il suffira pour vous qu\'il lit dans les pensées, Qu\'il connaît l\'avenir et les choses passées ; Rien n\'est secret pour lui dans tout cet univers, Et pour lui nos destins sont des livres ouverts. Moi-même, ainsi que vous, je ne pouvais le croire : Mais sitôt qu\'il me vit, il me dit mon histoire ; Et je fus étonné d\'entendre le discours Des traits les plus cachés de toutes mes amours.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Vous m\'en dites beaucoup.' },
    { k: 'perso', t: 'DORANTE' },
    { k: 'ligne', t: 'J\'en ai vu davantage.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Vous essayez en vain de me donner courage ; Mes soins et mes travaux verront, sans aucun fruit, Clore mes tristes jours d\'une éternelle nuit.' },
    { k: 'perso', t: 'DORANTE' },
    { k: 'ligne', t: 'Depuis que j\'ai quitté le séjour de Bretagne Pour venir faire ici le noble de campagne, Et que deux ans d\'amour, par une heureuse fin, M\'ont acquis Sylvérie et ce château voisin, De pas un, que je sache, il n\'a déçu l\'attente : Quiconque le consulte en sort l\'âme contente. Croyez-moi, son secours n\'est pas à négliger : D\'ailleurs, il est ravi quand il peut m\'obliger ; Et j\'ose me vanter qu\'un peu de mes prières Vous obtiendra de lui des faveurs singulières.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Le sort m\'est trop cruel pour devenir si doux.' },
    { k: 'perso', t: 'DORANTE' },
    { k: 'ligne', t: 'Espérez mieux : il sort, et s\'avance vers nous. Regardez-le marcher ; ce visage si grave, Dont le rare savoir tient la nature esclave, N\'a sauvé toutefois des ravages du temps Qu\'un peu d\'os et de nerfs qu\'ont décharnés cent ans, Son corps, malgré son âge, a les forces robustes, Le mouvement facile, et les démarches justes : Des ressorts inconnus agitent le vieillard, Et font de tous ses pas des miracles de l\'art.' },
    { k: 'scene', t: 'Scène II' },
    { k: 'didascalie', t: '(ALCANDRE, PRIDAMANT, DORANTE.)' },
    { k: 'perso', t: 'DORANTE' },
    { k: 'ligne', t: 'Grand démon du savoir, de qui les doctes veilles Produisent chaque jour de nouvelles merveilles, À qui rien n\'est secret dans nos intentions, Et qui vois, sans nous voir, toutes nos actions ; Si de ton art divin le pouvoir admirable Jamais en ma faveur se rendit secourable, De ce père affligé soulage les douleurs ; Une vieille amitié prend part en ses malheurs. Rennes, ainsi qu\'à moi, lui donna la naissance, Et presque entre ses bras j\'ai passé mon enfance ; Là son fils, pareil d\'âge et de condition, S\'unissant avec moi d\'étroite affection…' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Dorante, c\'est assez, je sais ce qui l\'amène ; Ce fils est aujourd\'hui le sujet de sa peine. Vieillard, n\'est-il pas vrai que son éloignement Par un juste remords te gêne incessamment ? Qu\'une obstination à te montrer sévère L\'a banni de ta vue, et cause ta misère ? Qu\'en vain, au repentir de ta sévérité, Tu cherches en tous lieux ce fils si maltraité ?' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Oracle de nos jours, qui connais toutes choses, En vain de ma douleur je cacherais les causes ; Tu sais trop quelle fut mon injuste rigueur, Et vois trop clairement les secrets de mon cœur. Il est vrai, j\'ai failli ; mais, pour mes injustices, Tant de travaux en vain sont d\'assez grands supplices : Donne enfin quelque borne à mes regrets cuisants, Rends-moi l\'unique appui de mes débiles ans. Je le tiendrai rendu, si j\'en ai des nouvelles ; L\'amour pour le trouver me fournira des ailes. Où fait-il sa retraite ? en quels lieux dois-je aller ? Fût-il au bout du monde, on m\'y verra voler.' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Commencez d\'espérer ; vous saurez par mes charmes Ce que le ciel vengeur refusait à vos larmes. Vous reverrez ce fils plein de vie et d\'honneur : De son bannissement il tire son bonheur. C\'est peu de vous le dire : en faveur de Dorante. Je veux vous faire voir sa fortune éclatante. Les novices de l\'art, avec tous leurs encens, Et leurs mots inconnus, qu\'ils feignent tout puissants, Leurs herbes, leurs parfums et leurs cérémonies, Apportent au métier des longueurs infinies, Qui ne sont, après tout, qu\'un mystère pipeur, Pour se faire valoir, et pour vous faire peur : Ma baguette à la main, j\'en ferai davantage.' },
    { k: 'didascalie', t: '(Il donne un coup de baguette, et on tire un rideau, derrière lequel sont en parade les plus beaux habits des comédiens.)' },
    { k: 'ligne', t: 'Jugez de votre fils par un tel équipage : Eh bien, celui d\'un prince a-t-il plus de splendeur ? Et pouvez-vous encor douter de sa grandeur ?' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'D\'un amour paternel vous flattez les tendresses ; Mon fils n\'est point de rang à porter ces richesses, Et sa condition ne saurait consentir Que d\'une telle pompe il s\'ose revêtir.' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Sous un meilleur destin sa fortune rangée, Et sa condition avec le temps changée, Personne maintenant n\'a de quoi murmurer Qu\'en public de la sorte il aime à se parer.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'À cet espoir si doux j\'abandonne mon âme : Mais parmi ces habits je vois ceux d\'une femme ; Serait-il marié ?' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Je vais de ses amours Et de tous ses hasards vous faire le discours. Toutefois, si votre âme était assez hardie, Sous une illusion vous pourriez voir sa vie, Et tous ses accidents devant vous exprimés Par des spectres pareils à des corps animés ; Il ne leur manquera ni geste ni parole.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Ne me soupçonnez point d\'une crainte frivole ; Le portrait de celui que je cherche en tous lieux Pourrait-il, par sa vue, épouvanter mes yeux ?' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'didascalie', t: '(à Dorante.)' },
    { k: 'ligne', t: 'Mon cavalier, de grâce, il faut faire retraite, Et souffrir qu\'entre nous l\'histoire en soit secrète.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Pour un si bon ami je n\'ai point de secrets.' },
    { k: 'perso', t: 'DORANTE' },
    { k: 'didascalie', t: '(à Pridamant.)' },
    { k: 'ligne', t: 'Il nous faut, sans réplique, accepter ses arrêts ; Je vous attends chez moi.' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Ce soir, si bon lui semble, Il vous apprendra tout quand vous serez ensemble.' },
    { k: 'scene', t: 'Scène III' },
    { k: 'didascalie', t: '(ALCANDRE, PRIDAMANT.)' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Votre fils tout d\'un coup ne fut pas grand seigneur ; Toutes ses actions ne vous font pas honneur, Et je serais marri d\'exposer sa misère En spectacle à des yeux autres que ceux d\'un père. Il vous prit quelque argent, mais ce petit butin À peine lui dura du soir jusqu\'au matin ; Et pour gagner Paris, il vendit par la plaine Des brevets à chasser la fièvre et la migraine, Dit la bonne aventure, et s\'y rendit ainsi. Là, comme on vit d\'esprit, il en vécut aussi. Dedans Saint-Innocent il se fit secrétaire : Après, montant d\'état, il fut clerc d\'un notaire. Ennuyé de la plume, il le quitta soudain, Et fit danser un singe au faubourg Saint-Germain. Il se mit sur la rime, et l\'essai de sa veine Enrichit les chanteurs de la Samaritaine. Son style prit après de plus beaux ornements ; Il se hasarda même à faire des romans, Des chansons pour Gautier, des pointes pour Guillaume. Depuis, il trafiqua de chapelets, de baume, Vendit du mithridate en maître opérateur, Revint dans le palais, et fut solliciteur. Enfin, jamais Buscon, Lazarille de Tormes, Sayavèdre, et Gusman, ne prirent tant de formes. C\'était là pour Dorante un honnête entretien !' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Que je vous suis tenu de ce qu\'il n\'en sait rien !' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Sans vous faire rien voir, je vous en fais un conte, Dont le peu de longueur épargne votre honte. Las de tant de métiers sans bonheur et sans fruit, Quelque meilleur destin à Bordeaux l\'a conduit ; Et là, comme il pensait au choix d\'un exercice, Un brave du pays l\'a pris à son service. Ce guerrier amoureux en a fait son agent : Cette commission l\'a remeublé d\'argent ; Il sait avec adresse, en portant les paroles, De la vaillante dupe attraper les pistoles ; Même de son agent il s\'est fait son rival, Et la beauté qu\'il sert ne lui veut point de mal. Lorsque de ses amours vous aurez vu l\'histoire, Je vous le veux montrer plein d\'éclat et de gloire, Et la même action qu\'il pratique aujourd\'hui.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Que déjà cet espoir soulage mon ennui !' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Il a caché son nom en battant la campagne, Et s\'est fait de Clindor le sieur de la Montagne ; C\'est ainsi que tantôt vous l\'entendrez nommer. Voyez tout sans rien dire, et sans vous alarmer. Je tarde un peu beaucoup pour votre impatience : N\'en concevez pourtant aucune défiance : C\'est qu\'un charme ordinaire a trop peu de pouvoir Sur les spectres parlants qu\'il faut vous faire voir. Entrons dedans ma grotte, afin que j\'y prépare Quelques charmes nouveaux pour un effet si rare.' },
    { k: 'acte', t: 'ACTE II' },
    { k: 'scene', t: 'Scène I' },
    { k: 'didascalie', t: '(ALCANDRE, PRIDAMANT.)' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Quoi qu\'il s\'offre à nos yeux, n\'en ayez point d\'effroi : De ma grotte surtout ne sortez qu\'après moi ; Sinon, vous êtes mort. Voyez déjà paraître Sous deux fantômes vains votre fils et son maître.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'O dieux ! je sens mon âme après lui s\'envoler.' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Faites-lui du silence, et l\'écoutez parler.' },
    { k: 'didascalie', t: '(Alcandre et Pridamant se retirent dans un des côtés du théâtre.)' },
    { k: 'scene', t: 'Scène II' },
    { k: 'didascalie', t: '(MATAMORE, CLINDOR.)' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Quoi ! monsieur, vous rêvez ! et cette âme hautaine, Après tant de beaux faits, semble être encore en peine ! N\'êtes-vous point lassé d\'abattre des guerriers ? Et vous faut-il encor quelques nouveaux lauriers ?' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Il est vrai que je rêve, et ne saurais résoudre Lequel je dois des deux le premier mettre en poudre, Du grand sophi de Perse, ou bien du grand mogor.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Eh ! de grâce, monsieur, laissez-les vivre encor. Qu\'ajouterait leur perte à votre renommée ? D\'ailleurs, quand auriez-vous rassemblé votre armée ?' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Mon armée ? Ah, poltron ! ah, traître ! pour leur mort Tu crois donc que ce bras ne soit pas assez fort ? Le seul bruit de mon nom renverse les murailles, Défait les escadrons, et gagne les batailles. Mon courage invaincu contre les empereurs N\'arme que la moitié de ses moindres fureurs ; D\'un seul commandement que je fais aux trois Parques, Je dépeuple l\'État des plus heureux monarques ; Le foudre est mon canon, les Destins mes soldats : Je couche d\'un revers mille ennemis à bas. D\'un souffle je réduis leurs projets en fumée ; Et tu m\'oses parler cependant d\'une armée ! Tu n\'auras plus l\'honneur de voir un second Mars ; Je vais t\'assassiner d\'un seul de mes regards, Veillaque : toutefois, je songe à ma maîtresse ; Ce penser m\'adoucit. Va, ma colère cesse, Et ce petit archer qui dompte tous les dieux Vient de chasser la mort qui logeait dans mes yeux. Regarde, j\'ai quitté cette effroyable mine Qui massacre, détruit, brise, brûle, extermine ; Et pensant au bel œil qui tient ma liberté, Je ne suis plus qu\'amour, que grâce, que beauté.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'O dieux ! en un moment que tout vous est possible ! Je vous vois aussi beau que vous étiez terrible, Et ne crois point d\'objet si ferme en sa rigueur, Qu\'il puisse constamment vous refuser son cœur.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Je te le dis encor, ne sois plus en alarme : Quand je veux, j\'épouvante ; et quand je veux, je charme ; Et, selon qu\'il me plaît, je remplis tour à tour Les hommes de terreur, et les femmes d\'amour. Du temps que ma beauté m\'était inséparable, Leurs persécutions me rendaient misérable ; Je ne pouvais sortir sans les faire pâmer ; Mille mouraient par jour à force de m\'aimer : J\'avais des rendez-vous de toutes les princesses ; Les reines, à l\'envi, mendiaient mes caresses ; Celle d\'Éthiopie, et celle du Japon, Dans leurs soupirs d\'amour ne mêlaient que mon nom. De passion pour moi deux sultanes troublèrent ; Deux autres, pour me voir, du sérail s\'échappèrent : J\'en fus mal quelque temps avec le Grand Seigneur.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Son mécontentement n\'allait qu\'à votre honneur.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Ces pratiques nuisaient à mes desseins de guerre, Et pouvaient m\'empêcher de conquérir la terre. D\'ailleurs, j\'en devins las ; et pour les arrêter, J\'envoyai le Destin dire à son Jupiter Qu\'il trouvât un moyen qui fît cesser les flammes Et l\'importunité dont m\'accablaient les dames : Qu\'autrement ma colère irait dedans les cieux Le dégrader soudain de l\'empire des dieux, Et donnerait à Mars à gouverner sa foudre. La frayeur qu\'il en eut le fit bientôt résoudre : Ce que je demandais fut prêt en un moment ; Et depuis, je suis beau quand je veux seulement.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Que j\'aurais, sans cela, de poulets à vous rendre !' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'De quelle que ce soit, garde-toi bien d\'en prendre, Sinon de… Tu m\'entends ? Que dit-elle de moi ?' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Que vous êtes des cœurs et le charme et l\'effroi ; Et que si quelque effet peut suivre vos promesses, Son sort est plus heureux que celui des déesses.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Écoute. En ce temps-là, dont tantôt je parlois, Les déesses aussi se rangeaient sous mes lois ; Et je te veux conter une étrange aventure Qui jeta du désordre en toute la nature, Mais désordre aussi grand qu\'on en voie arriver. Le Soleil fut un jour sans se pouvoir lever, Et ce visible dieu, que tant de monde adore, Pour marcher devant lui ne trouvait point d\'Aurore : On la cherchait partout, au lit du vieux Tithon, Dans les bois de Céphale, au palais de Memnon ; Et faute de trouver cette belle fourrière, Le jour jusqu\'à midi se passa sans lumière.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Où pouvait être alors la reine des clartés ?' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Au milieu de ma chambre à m\'offrir ses beautés : Elle y perdit son temps, elle y perdit ses larmes ; Mon cœur fut insensible à ses plus puissants charmes ; Et tout ce qu\'elle obtint pour son frivole amour Fut un ordre précis d\'aller rendre le jour.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Cet étrange accident me revient en mémoire ; J\'étais lors en Mexique, où j\'en appris l\'histoire, Et j\'entendis conter que la Perse en courroux De l\'affront de son dieu murmurait contre vous.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'J\'en ouïs quelque chose, et je l\'eusse punie ; Mais j\'étais engagé dans la Transylvanie, Où ses ambassadeurs, qui vinrent l\'excuser, À force de présents me surent apaiser.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Que la clémence est belle en un si grand courage !' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Contemple, mon ami, contemple ce visage ; Tu vois un abrégé de toutes les vertus. D\'un monde d\'ennemis sous mes pieds abattus, Dont la race est périe, et la terre déserte, Pas un qu\'à son orgueil n\'a jamais dû sa perte. Tous ceux qui font hommage à mes perfections Conservent leurs États par leurs submissions. En Europe, où les rois sont d\'une humeur civile, Je ne leur rase point de château ni de ville ; Je les souffre régner : mais, chez les Africains, Partout où j\'ai trouvé des rois un peu trop vains, J\'ai détruit les pays pour punir leurs monarques ; Et leurs vastes déserts en sont de bonnes marques ; Ces grands sables qu\'à peine on passe sans horreur Sont d\'assez beaux effets de ma juste fureur.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Revenons à l\'amour : voici votre maîtresse.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Ce diable de rival l\'accompagne sans cesse.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Où vous retirez-vous ?' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Ce fat n\'est pas vaillant, Mais il a quelque humeur qui le rend insolent. Peut-être qu\'orgueilleux d\'être avec cette belle, Il serait assez vain pour me faire querelle.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Ce serait bien courir lui-même à son malheur.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Lorsque j\'ai ma beauté, je n\'ai point de valeur.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Cessez d\'être charmant, et faites-vous terrible.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Mais tu n\'en prévois pas l\'accident infaillible : Je ne saurais me faire effroyable à demi ; Je tuerais ma maîtresse avec mon ennemi. Attendons en ce coin l\'heure qui les sépare.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Comme votre valeur, votre prudence est rare.' },
    { k: 'scene', t: 'Scène III' },
    { k: 'didascalie', t: '(ADRASTE, ISABELLE.)' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Hélas ! s\'il est ainsi, quel malheur est le mien ! Je soupire, j\'endure, et je n\'avance rien ; Et malgré les transports de mon amour extrême, Vous ne voulez pas croire encor que je vous aime.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je ne sais pas, monsieur, de quoi vous me blâmez. Je me connais aimable, et crois que vous m\'aimez ; Dans vos soupirs ardents j\'en vois trop d\'apparence ; Et quand bien de leur part j\'aurais moins d\'assurance, Pour peu qu\'un honnête homme ait vers moi de crédit, Je lui fais la faveur de croire ce qu\'il dit. Rendez-moi la pareille ; et puisqu\'à votre flamme Je ne déguise rien de ce que j\'ai dans l\'âme, Faites-moi la faveur de croire sur ce point Que, bien que vous m\'aimiez, je ne vous aime point.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Cruelle, est-ce là donc ce que vos injustices Ont réservé de prix à de si longs services ? Et mon fidèle amour est-il si criminel Qu\'il doive être puni d\'un mépris éternel ?' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Nous donnons bien souvent de divers noms aux choses : Des épines pour moi, vous les nommez des roses ; Ce que vous appelez service, affection, Je l\'appelle supplice et persécution. Chacun dans sa croyance également s\'obstine. Vous pensez m\'obliger d\'un feu qui m\'assassine ; Et ce que vous jugez digne du plus haut prix Ne mérite, à mon gré, que haine et que mépris.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'N\'avoir que du mépris pour des flammes si saintes Dont j\'ai reçu du ciel les premières atteintes ! Oui, le ciel, au moment qu\'il me fit respirer, Ne me donna de cœur que pour vous adorer. Mon âme vint au jour pleine de votre idée ; Avant que de vous voir vous l\'avez possédée ; Et quand je me rendis à des regards si doux, Je ne vous donnai rien qui ne fût tout à vous, Rien que l\'ordre du ciel n\'eût déjà fait tout vôtre.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Le ciel m\'eût fait plaisir d\'en enrichir une autre ; Il vous fit pour m\'aimer, et moi pour vous haïr : Gardons-nous bien tous deux de lui désobéir. Vous avez, après tout, bonne part à sa haine, Ou d\'un crime secret il vous livre à la peine ; Car je ne pense pas qu\'il soit tourment égal Au supplice d\'aimer qui vous traite si mal.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'La grandeur de mes maux vous étant si connue, Me refuserez-vous la pitié qui m\'est due ?' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Certes j\'en ai beaucoup, et vous plains d\'autant plus Que je vois ces tourments tout à fait superflus, Et n\'avoir pour tout fruit d\'une longue souffrance Que l\'incommode honneur d\'une triste constance.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Un père l\'autorise, et mon feu maltraité Enfin aura recours à son autorité.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Ce n\'est pas le moyen de trouver votre compte ; Et d\'un si beau dessein vous n\'aurez que la honte.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'J\'espère voir pourtant, avant la fin du jour, Ce que peut son vouloir au défaut de l\'amour.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Et moi, j\'espère voir, avant que le jour passe, Un amant accablé de nouvelle disgrâce.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Eh quoi ! cette rigueur ne cessera jamais ?' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Allez trouver mon père, et me laissez en paix.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Votre âme, au repentir de sa froideur passée, Ne la veut point quitter sans être un peu forcée ; J\'y vais tout de ce pas, mais avec des serments Que c\'est pour obéir à vos commandements.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Allez continuer une vaine poursuite.' },
    { k: 'scene', t: 'Scène IV' },
    { k: 'didascalie', t: '(MATAMORE, ISABELLE, CLINDOR.)' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Eh bien, dès qu\'il m\'a vu, comme a-t-il pris la fuite ! M\'a-t-il bien su quitter la place au même instant !' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Ce n\'est pas honte à lui, les rois en font autant, Du moins si ce grand bruit qui court de vos merveilles N\'a trompé mon esprit en frappant mes oreilles.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Vous le pouvez bien croire ; et pour le témoigner, Choisissez en quels lieux il vous plaît de régner ; Ce bras tout aussitôt vous conquête un empire : J\'en jure par lui-même, et cela c\'est tout dire.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Ne prodiguez pas tant ce bras toujours vainqueur ; Je ne veux point régner que dessus votre cœur : Toute l\'ambition que me donne ma flamme, C\'est d\'avoir pour sujets les désirs de votre âme.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Ils vous sont tout acquis, et pour vous faire voir Que vous avez sur eux un absolu pouvoir, Je n\'écouterai plus cette humeur de conquête ; Et laissant tous les rois leurs couronnes en tête, J\'en prendrai seulement deux ou trois pour valets, Qui viendront à genoux vous rendre mes poulets.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'L\'éclat de tels suivants attirerait l\'envie Sur le rare bonheur où je coule ma vie ; Le commerce discret de nos affections N\'a besoin que de lui pour ces commissions.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Vous avez, Dieu me sauve ! un esprit à ma mode ; Vous trouvez, comme moi, la grandeur incommode. Les sceptres les plus beaux n\'ont rien pour moi d\'exquis ; Je les rends aussitôt que je les ai conquis, Et me suis vu charmer quantité de princesses, Sans que jamais mon cœur les voulût pour maîtresses.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Certes, en ce point seul je manque un peu de foi. Que vous ayez quitté des princesses pour moi ! Que vous leur refusiez un cœur dont je dispose !' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'didascalie', t: '(montrant Clindor.)' },
    { k: 'ligne', t: 'Je crois que la Montagne en saura quelque chose. Viens çà. Lorsqu\'en la Chine, en ce fameux tournoi, Je donnai dans la vue aux deux filles du roi, Que te dit-on en cour de cette jalousie Dont pour moi toutes deux eurent l\'âme saisie ?' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Par vos mépris enfin l\'une et l\'autre mourut. J\'étais lors en Egypte, où le bruit en courut ; Et ce fut en ce temps que la peur de vos armes Fit nager le grand Caire en un fleuve de larmes. Vous veniez d\'assommer dix géants en un jour ; Vous aviez désolé les pays d\'alentour, Rasé quinze châteaux, aplani deux montagnes, Fait passer par le feu villes, bourgs et campagnes, Et défait, vers Damas, cent mille combattants.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Que tu remarques bien et les lieux et les temps ! Je l\'avais oublié.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Des faits si pleins de gloire Vous peuvent-ils ainsi sortir de la mémoire ?' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Trop pleine de lauriers remportés sur les rois, Je ne la charge point de ces menus exploits.' },
    { k: 'scene', t: 'Scène V' },
    { k: 'didascalie', t: '(MATAMORE, ISABELLE, CLINDOR, PAGE.)' },
    { k: 'perso', t: 'PAGE' },
    { k: 'ligne', t: 'Monsieur.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Que veux-tu, page ?' },
    { k: 'perso', t: 'PAGE' },
    { k: 'ligne', t: 'Un courrier vous demande' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'D\'où vient-il ?' },
    { k: 'perso', t: 'PAGE' },
    { k: 'ligne', t: 'De la part de la reine d\'Islande.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Ciel, qui sais comme quoi j\'en suis persécuté, Un peu plus de repos avec moins de beauté ; Fais qu\'un si long mépris enfin la désabuse.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Voyez ce que pour vous ce grand guerrier refuse.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je n\'en puis plus douter.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Il vous le disait bien.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Elle m\'a beau prier, non, je n\'en ferai rien. Et quoi qu\'un fol espoir ose encor lui promettre, Je lui vais envoyer sa mort dans une lettre. Trouvez-le bon, ma reine, et souffrez cependant Une heure d\'entretien de ce cher confident, Qui, comme de ma vie il sait toute l\'histoire, Vous fera voir sur qui vous avez la victoire.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Tardez encore moins ; et par ce prompt retour, Je jugerai quel est envers moi votre amour.' },
    { k: 'scene', t: 'Scène VI' },
    { k: 'didascalie', t: '(CLINDOR, ISABELLE.)' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Jugez plutôt par là l\'humeur du personnage : Ce page n\'est chez lui que pour ce badinage, Et venir d\'heure en heure avertir sa grandeur D\'un courrier, d\'un agent, ou d\'un ambassadeur.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Ce message me plaît bien plus qu\'il ne lui semble ; Il me défait d\'un fou pour nous laisser ensemble.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Ce discours favorable enhardira mes feux A bien user du temps si propice à mes vœux.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Que m\'allez-vous conter ?' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Que j\'adore Isabelle, Que je n\'ai plus de cœur ni d\'âme que pour elle ; Que ma vie…' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Épargnez ces propos superflus ; Je les sais, je les crois : que voulez-vous de plus ? Je néglige à vos yeux l\'offre d\'un diadème ; Je dédaigne un rival : en un mot, je vous aime. C\'est aux commencements des faibles passions À s\'amuser encore aux protestations : Il suffit de nous voir au point où sont les nôtres ; Un coup d\'œil vaut pour vous tous les discours des autres.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Dieux ! qui l\'eût jamais cru que mon sort rigoureux Se rendît si facile à mon cœur amoureux ! Banni de mon pays par la rigueur d\'un père, Sans support, sans amis, accablé de misère, Et réduit à flatter le caprice arrogant Et les vaines humeurs d\'un maître extravagant ; Ce pitoyable état de ma triste fortune N\'a rien qui vous déplaise ou qui vous importune ; Et d\'un rival puissant les biens et la grandeur Obtiennent moins sur vous que ma sincère ardeur.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'C\'est comme il faut choisir. Un amour véritable S\'attache seulement à ce qu\'il voit aimable. Qui regarde les biens ou la condition N\'a qu\'un amour avare, ou plein d\'ambition, Et souille lâchement par ce mélange infâme Les plus nobles désirs qu\'enfante une belle âme. Je sais bien que mon père a d\'autres sentiments, Et mettra de l\'obstacle à nos contentements : Mais l\'amour sur mon cœur a pris trop de puissance Pour écouter encor les lois de la naissance. Mon père peut beaucoup, mais bien moins que ma foi. Il a choisi pour lui, je veux choisir pour moi.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Confus de voir donner à mon peu de mérite…' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Voici mon importun, souffrez que je l\'évite.' },
    { k: 'scene', t: 'Scène VII' },
    { k: 'didascalie', t: '(ADRASTE, CLINDOR.)' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Que vous êtes heureux ! et quel malheur me suit ! Ma maîtresse vous souffre, et l\'ingrate me fuit. Quelque goût qu\'elle prenne en votre compagnie, Sitôt que j\'ai paru, mon abord l\'a bannie.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Sans avoir vu vos pas s\'adresser en ce lieu, Lasse de mes discours, elle m\'a dit adieu.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Lasse de vos discours ! votre humeur est trop bonne, Et votre esprit trop beau pour ennuyer personne. Mais que lui contiez-vous qui pût l\'importuner ?' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Des choses qu\'aisément vous pouvez deviner. Les amours de mon maître, ou plutôt ses sottises, Ses conquêtes en l\'air, ses hautes entreprises.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Voulez-vous m\'obliger ? votre maître, ni vous, N\'êtes pas gens tous deux à me rendre jaloux ; Mais si vous ne pouvez arrêter ses saillies, Divertissez ailleurs le cours de ses folies.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Que craignez-vous de lui, dont tous les compliments Ne parlent que de morts et de saccagements, Qu\'il bat, terrasse, brise, étrangle, brûle, assomme ?' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Pour être son valet, je vous trouve honnête homme ; Vous n\'êtes point de taille à servir sans dessein Un fanfaron plus fou que son discours n\'est vain. Quoi qu\'il en soit, depuis que je vous vois chez elle, Toujours de plus en plus je l\'éprouve cruelle : Ou vous servez quelque autre, ou votre qualité Laisse dans vos projets trop de témérité. Je vous tiens fort suspect de quelque haute adresse. Que votre maître, enfin, fasse une autre maîtresse ; Ou, s\'il ne peut quitter un entretien si doux, Qu\'il se serve du moins d\'un autre que de vous. Ce n\'est pas qu\'après tout les volontés d\'un père, Qui sait ce que je suis, ne terminent l\'affaire ; Mais purgez-moi l\'esprit de ce petit souci, Et si vous vous aimez, bannissez-vous d\'ici ; Car si je vous vois plus regarder cette porte, Je sais comme traiter les gens de votre sorte.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Me prenez-vous pour homme à nuire à votre feu ?' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Sans réplique, de grâce, ou nous verrons beau jeu. Allez ; c\'est assez dit.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Pour un léger ombrage, C\'est trop indignement traiter un bon courage. Si le ciel en naissant ne m\'a fait grand seigneur, Il m\'a fait le cœur ferme et sensible à l\'honneur : Et je pourrais bien rendre un jour ce qu\'on me prête.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Quoi ! vous me menacez !' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Non, non, je fais retraite. D\'un si cruel affront vous aurez peu de fruit ; Mais ce n\'est pas ici qu\'il faut faire du bruit.' },
    { k: 'scene', t: 'Scène VIII' },
    { k: 'didascalie', t: '(ADRASTE, LYSE.)' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Ce belître insolent me fait encor bravade.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'À ce compte, monsieur, votre esprit est malade ?' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Malade, mon esprit !' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Oui, puisqu\'il est jaloux Du malheureux agent de ce prince des fous.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Je sais ce que je suis, et ce qu\'est Isabelle, Et crains peu qu\'un valet me supplante auprès d\'elle. Je ne puis toutefois souffrir sans quelque ennui Le plaisir qu\'elle prend à causer avec lui.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'C\'est dénier ensemble et confesser la dette.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Nomme, si tu le veux, ma boutade indiscrète, Et trouve mes soupçons bien ou mal à propos, Je l\'ai chassé d\'ici pour me mettre en repos. En effet, qu\'en est-il ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Si j\'ose vous le dire, Ce n\'est plus que pour lui qu\'Isabelle soupire.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Lyse, que me dis-tu ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Qu\'il possède son cœur, Que jamais feux naissants n\'eurent tant de vigueur, Qu\'ils meurent l\'un pour l\'autre, et n\'ont qu\'une pensée.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Trop ingrate beauté, déloyale, insensée, Tu m\'oses donc ainsi préférer un maraud ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Ce rival orgueilleux le porte bien plus haut, Et je vous en veux faire entière confidence : Il se dit gentilhomme, et riche.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Ah ! l\'impudence !' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'D\'un père rigoureux fuyant l\'autorité, Il a couru longtemps d\'un et d\'autre côté ; Enfin, manque d\'argent peut-être, ou par caprice, De notre fier-à-bras il s\'est mis au service, Et, sous ombre d\'agir pour ses folles amours, Il a su pratiquer de si rusés détours, Et charmer tellement cette pauvre abusée, Que vous en avez vu votre ardeur méprisée : Mais parlez à son père, et bientôt son pouvoir Remettra son esprit aux termes du devoir.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Je viens tout maintenant d\'en tirer assurance De recevoir les fruits de ma persévérance, Et devant qu\'il soit peu nous en verrons l\'effet : Mais écoute, il me faut obliger tout à fait.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Où je vous puis servir j\'ose tout entreprendre.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Peux-tu dans leurs amours me les faire surprendre ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Il n\'est rien plus aisé ; peut-être dès ce soir.' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Adieu donc. Souviens-toi de me les faire voir.' },
    { k: 'didascalie', t: '(Il lui donne un diamant.)' },
    { k: 'ligne', t: 'Cependant prends ceci seulement par avance.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Que le galant alors soit frotté d\'importance !' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Crois-moi qu\'il se verra, pour te mieux contenter, Chargé d\'autant de bois qu\'il en pourra porter.' },
    { k: 'scene', t: 'Scène IX' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'L\'arrogant croit déjà tenir ville gagnée ; Mais il sera puni de m\'avoir dédaignée. Parce qu\'il est aimable, il fait le petit dieu, Et ne veut s\'adresser qu\'aux filles de bon lieu. Je ne mérite pas l\'honneur de ses caresses : Vraiment c\'est pour son nez, il lui faut des maîtresses ; Je ne suis que servante : et qu\'est-il que valet ? Si son visage est beau, le mien n\'est pas trop laid : Il se dit riche et noble, et cela me fait rire ; Si loin de son pays, qui n\'en peut autant dire ? Qu\'il le soit, nous verrons ce soir, si je le tiens, Danser sous le cotret sa noblesse et ses biens.' },
    { k: 'scene', t: 'Scène X' },
    { k: 'didascalie', t: '(ALCANDRE, PRIDAMANT.)' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Le cœur vous bat un peu.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Je crains cette menace.' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Lyse aime trop Clindor pour causer sa disgrâce.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Elle en est méprisée, et cherche à se venger.' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Ne craignez point : l\'amour la fera bien changer.' },
    { k: 'acte', t: 'ACTE III' },
    { k: 'scene', t: 'Scène I' },
    { k: 'didascalie', t: '(GÉRONTE, ISABELLE.)' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'Apaisez vos soupirs et tarissez vos larmes ; Contre ma volonté ce sont de faibles armes : Mon cœur, quoique sensible à toutes vos douleurs, Ecoute la raison, et néglige vos pleurs. Je sais ce qu\'il vous faut beaucoup mieux que vous-même. Vous dédaignez Adraste à cause que je l\'aime ; Et parce qu\'il me plaît d\'en faire votre époux, Votre orgueil n\'y voit rien qui soit digne de vous. Quoi ! manque-t-il de bien, de cœur ou de noblesse ? En est-ce le visage ou l\'esprit qui vous blesse ? Il vous fait trop d\'honneur.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je sais qu\'il est parfait, Et que je réponds mal à l\'honneur qu\'il me fait ; Mais si votre bonté me permet en ma cause, Pour me justifier, de dire quelque chose, Par un secret instinct, que je ne puis nommer, J\'en fais beaucoup d\'état, et ne le puis aimer. Souvent je ne sais quoi que le ciel nous inspire Soulève tout le cœur contre ce qu\'on désire, Et ne nous laisse pas en état d\'obéir Quand on choisit pour nous ce qu\'il nous fait haïr. Il attache ici-bas avec des sympathies Les âmes que son ordre a là-haut assorties : On n\'en saurait unir sans ses avis secrets ; Et cette chaîne manque où manquent ses décrets. Aller contre les lois de cette providence, C\'est le prendre à partie, et blâmer sa prudence, L\'attaquer en rebelle, et s\'exposer aux coups Des plus âpres malheurs qui suivent son courroux.' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'Insolente, est-ce ainsi que l\'on se justifie ? Quel maître vous apprend cette philosophie ? Vous en savez beaucoup ; mais tout votre savoir Ne m\'empêchera pas d\'user de mon pouvoir. Si le ciel pour mon choix vous donne tant de haine, Vous a-t-il mise en feu pour ce grand capitaine ? Ce guerrier valeureux vous tient-il dans ses fers ? Et vous a-t-il domptée avec tout l\'univers ? Ce fanfaron doit-il relever ma famille ?' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Eh ! de grâce, monsieur, traitez mieux votre fille !' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'Quel sujet donc vous porte à me désobéir ?' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Mon heur et mon repos, que je ne puis trahir. Ce que vous appelez un heureux hyménée N\'est pour moi qu\'un enfer si j\'y suis condamnée.' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'Ah ! qu\'il en est encor de mieux faites que vous Qui se voudraient bien voir dans un enfer si doux, Après tout, je le veux ; cédez à ma puissance.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Faites un autre essai de mon obéissance.' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'Ne me répliquez plus quand j\'ai dit : Je le veux. Rentrez ; c\'est désormais trop contesté nous deux.' },
    { k: 'scene', t: 'Scène II' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'Qu\'à présent la jeunesse a d\'étranges manies ! Les règles du devoir lui sont des tyrannies ; Et les droits les plus saints deviennent impuissants Contre cette fierté qui l\'attache à son sens. Telle est l\'humeur du sexe ; il aime à contredire, Rejette obstinément le joug de notre empire, Ne suit que son caprice en ses affections, Et n\'est jamais d\'accord de nos élections. N\'espère pas pourtant, aveugle et sans cervelle, Que ma prudence cède à ton esprit rebelle. Mais ce fou viendra-t-il toujours m\'embarrasser ? Par force ou par adresse il me le faut chasser.' },
    { k: 'scene', t: 'Scène III' },
    { k: 'didascalie', t: '(GÉRONTE, MATAMORE, CLINDOR.)' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'didascalie', t: '(à Clindor.)' },
    { k: 'ligne', t: 'Ne doit-on pas avoir pitié de ma fortune ? Le grand vizir encor de nouveau m\'importune ; Le Tartare, d\'ailleurs, m\'appelle à son secours ; Narsingue et Calicut m\'en pressent tous les jours : Si je ne les refuse, il me faut mettre en quatre.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Pour moi, je suis d\'avis que vous les laissiez battre. Vous emploieriez trop mal vos invincibles coups Si pour en servir un vous faisiez trois jaloux.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Tu dis bien ; c\'est assez de telles courtoisies ; Je ne veux qu\'en amour donner des jalousies. Ah ! monsieur, excusez, si, faute de vous voir, Bien que si près de vous, je manquais au devoir. Mais quelle émotion paraît sur ce visage ? Où sont vos ennemis, que j\'en fasse carnage ?' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'Monsieur, grâces aux dieux, je n\'ai point d\'ennemis.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Mais grâces à ce bras qui vous les a soumis.' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'C\'est une grâce encor que j\'avais ignorée.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Depuis que ma faveur pour vous s\'est déclarée, Ils sont tous morts de peur, ou n\'ont osé branler.' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'C\'est ailleurs, maintenant, qu\'il vous faut signaler : Il fait beau voir ce bras, plus craint que le tonnerre, Demeurer si paisible en un temps plein de guerre ; Et c\'est pour acquérir un nom bien relevé, D\'être dans une ville à battre le pavé. Chacun croit votre gloire à faux titre usurpée, Et vous ne passez plus que pour traîneur d\'épée.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Ah, ventre ! il est tout vrai que vous avez raison ; Mais le moyen d\'aller, si je suis en prison ? Isabelle m\'arrête, et ses yeux pleins de charmes Ont captivé mon cœur et suspendu mes armes.' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'Si rien que son sujet ne vous tient arrêté, Faites votre équipage en toute liberté ; Elle n\'est pas pour vous ; n\'en soyez point en peine.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Ventre ! que dites-vous ? je la veux faire reine.' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'Je ne suis pas d\'humeur à rire tant de fois Du grotesque récit de vos rares exploits. La sottise ne plaît qu\'alors qu\'elle est nouvelle : En un mot, faites reine une autre qu\'Isabelle. Si pour l\'entretenir vous venez plus ici…' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Il a perdu le sens de me parler ainsi. Pauvre homme, sais-tu bien que mon nom effroyable Met le Grand Turc en fuite, et fait trembler le diable ; Que pour t\'anéantir je ne veux qu\'un moment ?' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'J\'ai chez moi des valets à mon commandement, Qui, n\'ayant pas l\'esprit de faire des bravades, Répondraient de la main à vos rodomontades.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'didascalie', t: '(à Clindor.)' },
    { k: 'ligne', t: 'Dis-lui ce que j\'ai fait en mille et mille lieux.' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'Adieu. Modérez-vous, il vous en prendra mieux. Bien que je ne sois pas de ceux qui vous haïssent, J\'ai le sang un peu chaud, et mes gens m\'obéissent.' },
    { k: 'scene', t: 'Scène IV' },
    { k: 'didascalie', t: '(MATAMORE, CLINDOR.)' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Respect de ma maîtresse, incommode vertu, Tyran de ma vaillance, à quoi me réduis-tu ? Que n\'ai-je eu cent rivaux en la place d\'un père, Sur qui, sans t\'offenser, laisser choir ma colère ! Ah ! visible démon, vieux spectre décharné, Vrai suppôt de Satan, médaille de damné, Tu m\'oses donc bannir, et même avec menaces, Moi, de qui tous les rois briguent les bonnes grâces ?' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Tandis qu\'il est dehors, allez, dès aujourd\'hui, Causer de vos amours et vous moquer de lui.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Cadédiou ! ses valets feraient quelque insolence.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Ce fer a trop de quoi dompter leur violence.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Oui, mais les feux qu\'il jette en sortant de prison Auraient en un moment embrasé la maison, Dévoré tout à l\'heure ardoises et gouttières, Faîtes, lattes, chevrons, montants, courbes, filières, Entre-toises, sommiers, colonnes, soliveaux, Pannes, soles, appuis, jambages, traveteaux, Portes, grilles, verrous, serrures, tuiles, pierres, Plomb, fer, plâtre, ciment, peinture, marbre, verres, Caves, puits, cours, perrons, salles, chambres, greniers, Offices, cabinets, terrasses, escaliers. Juge un peu quel désordre aux yeux de ma charmeuse ; Ces feux étoufferaient son ardeur amoureuse. Va lui parler pour moi, toi qui n\'es pas vaillant ; Tu puniras à moins un valet insolent.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'C\'est m\'exposer…' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Adieu : je vois ouvrir la porte, Et crains que sans respect cette canaille sorte.' },
    { k: 'scene', t: 'Scène V' },
    { k: 'didascalie', t: '(CLINDOR, LYSE.)' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'didascalie', t: '(SEUL)' },
    { k: 'ligne', t: 'Le souverain poltron, à qui pour faire peur Il ne faut qu\'une feuille, une ombre, une vapeur ! Un vieillard le maltraite, il fuit pour une fille, Et tremble à tous moments de crainte qu\'on l\'étrille. Lyse, que ton abord doit être dangereux ! Il donne l\'épouvante à ce cœur généreux, Cet unique vaillant, la fleur des capitaines, Qui dompte autant de rois qu\'il captive de reines !' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Mon visage est ainsi malheureux en attraits ; D\'autres charment de loin, le mien fait peur de près.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'S\'il fait peur à des fous, il charme les plus sages. Il n\'est pas quantité de semblables visages. Si l\'on brûle pour toi, ce n\'est pas sans sujet ; Je ne connus jamais un si gentil objet ; L\'esprit beau, prompt, accort, l\'humeur un peu railleuse, L\'embonpoint ravissant, la taille avantageuse, Les yeux doux, le teint vif, et les traits délicats : Qui serait le brutal qui ne t\'aimerait pas ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'De grâce, et depuis quand me trouvez-vous si belle ? Voyez bien, je suis Lyse, et non pas Isabelle.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Vous partagez vous deux mes inclinations : J\'adore sa fortune, et tes perfections.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Vous en embrassez trop, c\'est assez pour vous d\'une, Et mes perfections cèdent à sa fortune.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Quelque effort que je fasse à lui donner ma foi, Penses-tu qu\'en effet je l\'aime plus que toi ? L\'amour et l\'hyménée ont diverse méthode ; L\'un court au plus aimable, et l\'autre au plus commode. Je suis dans la misère, et tu n\'as point de bien ; Un rien s\'ajuste mal avec un autre rien ; Et malgré les douceurs que l\'amour y déploie, Deux malheureux ensemble ont toujours courte joie. Ainsi j\'aspire ailleurs, pour vaincre mon malheur ; Mais je ne puis te voir sans un peu de douleur, Sans qu\'un soupir échappe à ce cœur qui murmure De ce qu\'à ses désirs ma raison fait d\'injure. A tes moindres coups d\'œil je me laisse charmer. Ah ! que je t\'aimerais, s\'il ne fallait qu\'aimer ! Et que tu me plairais, s\'il ne fallait que plaire !' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Que vous auriez d\'esprit, si vous saviez vous taire, Ou remettre du moins en quelque autre saison A montrer tant d\'amour avec tant de raison ! Le grand trésor pour moi qu\'un amoureux si sage, Qui, par compassion, n\'ose me rendre hommage, Et porte ses désirs à des partis meilleurs, De peur de m\'accabler sous nos communs malheurs ! Je n\'oublierai jamais de si rares mérites. Allez continuer cependant vos visites.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Que j\'aurais avec toi l\'esprit bien plus content !' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Ma maîtresse là-haut est seule, et vous attend.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Tu me chasses ainsi !' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Non, mais je vous envoie Aux lieux où vous aurez une plus longue joie.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Que même tes dédains me semblent gracieux !' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Ah, que vous prodiguez un temps si précieux ! Allez.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Souviens-toi donc que si j\'en aime une autre…' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'C\'est de peur d\'ajouter ma misère à la vôtre. Je vous l\'ai déjà dit, je ne l\'oublierai pas.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Adieu. Ta raillerie a pour moi tant d\'appas, Que mon cœur à tes yeux de plus en plus s\'engage, Et je t\'aimerais trop à tarder davantage.' },
    { k: 'scene', t: 'Scène VI' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'L\'ingrat ! il trouve enfin mon visage charmant, Et pour se divertir il contrefait l\'amant ! Qui néglige mes feux m\'aime par raillerie, Me prend pour le jouet de sa galanterie, Et, par un libre aveu de me voler sa foi, Me jure qu\'il m\'adore, et ne veut point de moi. Aime en tous lieux, perfide, et partage ton âme ; Choisis qui tu voudras pour maîtresse ou pour femme Donne à tes intérêts à ménager tes vœux ; Mais ne crois plus tromper aucune de nous deux. Isabelle vaut mieux qu\'un amour politique, Et je vaux mieux qu\'un cœur où cet amour s\'applique. J\'ai raillé comme toi, mais c\'était seulement Pour ne t\'avertir pas de mon ressentiment. Qu\'eût produit son éclat, que de la défiance ? Qui cache sa colère assure sa vengeance ; Et ma feinte douceur prépare beaucoup mieux Ce piège où tu vas choir, et bientôt, à mes yeux. Toutefois qu\'as-tu fait qui te rende coupable ? Pour chercher sa fortune est-on si punissable ? Tu m\'aimes, mais le bien te fait être inconstant : Au siècle où nous vivons, qui n\'en ferait autant ? Oublions des mépris où par force il s\'excite, Et laissons-le jouir du bonheur qu\'il mérite. S\'il m\'aime, il se punit en m\'osant dédaigner, Et si je l\'aime encor, je le dois épargner. Dieux ! à quoi me réduit ma folle inquiétude, De vouloir faire grâce à tant d\'ingratitude ? Digne soif de vengeance, à quoi m\'exposez-vous, De laisser affaiblir un si juste courroux ? Il m\'aime, et de mes yeux je m\'en vois méprisée ! Je l\'aime, et ne lui sers que d\'objet de risée ! Silence, amour, silence ; il est temps de punir. J\'en ai donné ma foi, laisse-moi la tenir ; Puisque ton faux espoir ne fait qu\'aigrir ma peine, Fais céder tes douceurs à celles de la haine. Il est temps qu\'en mon cœur elle règne à son tour, Et l\'amour outragé ne doit plus être amour.' },
    { k: 'scene', t: 'Scène VII' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Les voilà, sauvons-nous. Non, je ne vois personne. Avançons hardiment. Tout le corps me frissonne. Je les entends, fuyons. Le vent faisait ce bruit. Marchons sous la faveur des ombres de la nuit. Vieux rêveur, malgré toi j\'attends ici ma reine. Ces diables de valets me mettent bien en peine. De deux mille ans et plus, je ne tremblai si fort. C\'est trop me hasarder ; s\'ils sortent, je suis mort ; Car j\'aime mieux mourir que leur donner bataille, Et profaner mon bras contre cette canaille. Que le courage expose à d\'étranges dangers ! Toutefois, en tous cas, je suis des plus légers ; S\'il ne faut que courir, leur attente est dupée : J\'ai le pied pour le moins aussi bon que l\'épée. Tout de bon, je les vois : c\'est fait, il faut mourir : J\'ai le corps si glacé, que je ne puis courir. Destin, qu\'à ma valeur tu te montres contraire !… C\'est ma reine elle-même, avec mon secrétaire ! Tout mon corps se déglace : écoutons leurs discours, Et voyons son adresse à traiter mes amours.' },
    { k: 'scene', t: 'Scène VIII' },
    { k: 'didascalie', t: '(CLINDOR, ISABELLE, MATAMORE.)' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'didascalie', t: '(Matamore écoute caché.)' },
    { k: 'ligne', t: 'Tout se prépare mal du côté de mon père ; Je ne le vis jamais d\'une humeur si sévère : Il ne souffrira plus votre maître, ni vous ; Votre rival, d\'ailleurs, est devenu jaloux : C\'est par cette raison que je vous fais descendre ; Dedans mon cabinet ils pourraient nous surprendre ; Ici nous parlerons en plus de sûreté : Vous pourrez vous couler d\'un et d\'autre côté ; Et si quelqu\'un survient, ma retraite est ouverte.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'C\'est trop prendre de soin pour empêcher ma perte.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je n\'en puis prendre trop pour assurer un bien Sans qui tous autres biens à mes yeux ne sont rien, Un bien qui vaut pour moi la terre tout entière, Et pour qui seul enfin j\'aime à voir la lumière. Un rival par mon père attaque en vain ma foi ; Votre amour seul a droit de triompher de moi : Des discours de tous deux je suis persécutée ; Mais pour vous je me plais à me voir maltraitée. Et des plus grands malheurs je bénirais les coups, Si ma fidélité les endurait pour vous.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Vous me rendez confus, et mon âme ravie Ne vous peut, en revanche, offrir rien que ma vie ; Mon sang est le seul bien qui me reste en ces lieux, Trop heureux de le perdre en servant vos beaux yeux ! Mais si mon astre un jour, changeant son influence, Me donne un accès libre aux lieux de ma naissance, Vous verrez que ce choix n\'est pas fort inégal, Et que, tout balancé, je vaux bien mon rival. Mais, avec ces douceurs, permettez-moi de craindre Qu\'un père et ce rival ne veuillent vous contraindre.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'N\'en ayez point d\'alarme, et croyez qu\'en ce cas L\'un aura moins d\'effet que l\'autre n\'a d\'appas. Je ne vous dirai point où je suis résolue : Il suffit que sur moi je me rends absolue. Ainsi tous les projets sont des projets en l\'air. Ainsi…' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Je n\'en puis plus : il est temps de parler.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Dieux ! on nous écoutait.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'C\'est notre capitaine : Je vais bien l\'apaiser ; n\'en soyez pas en peine.' },
    { k: 'scene', t: 'Scène IX' },
    { k: 'didascalie', t: '(MATAMORE, CLINDOR.)' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Ah ! traître !' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Parlez bas, ces valets…' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Eh bien ! quoi ?' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Ils fondront tout à l\'heure et sur vous et sur moi.' },
    { k: 'didascalie', t: '(Matamore le tire en un coin du théâtre.)' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Viens çà. Tu sais ton crime, et qu\'à l\'objet que j\'aime, Loin de parler pour moi, tu parlais pour toi-même ?' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Oui, pour me rendre heureux j\'ai fait quelques efforts.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Je te donne le choix de trois ou quatre morts ; Je vais, d\'un coup de poing, te briser comme verre, Ou t\'enfoncer tout vif au centre de la terre, Ou te fendre en dix parts d\'un seul coup de revers, Ou te jeter si haut au-dessus des éclairs, Que tu sois dévoré des feux élémentaires. Choisis donc promptement, et pense à tes affaires.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Vous-même choisissez.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Quel choix proposes-tu ?' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'De fuir en diligence, ou d\'être bien battu.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Me menacer encore ! ah, ventre ! quelle audace ! Au lieu d\'être à genoux, et d\'implorer ma grâce !… Il a donné le mot, ces valets vont sortir… Je m\'en vais commander aux mers de t\'engloutir.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Sans vous chercher si loin un si grand cimetière, Je vous vais, de ce pas, jeter dans la rivière.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Ils sont d\'intelligence. Ah, tête !' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Point de bruit : J\'ai déjà massacré dix hommes cette nuit ; Et si vous me fâchez, vous en croîtrez le nombre.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Cadédiou ! ce coquin a marché dans mon ombre ; Il s\'est fait tout vaillant d\'avoir suivi mes pas : S\'il avait du respect, j\'en voudrais faire cas. Ecoute : je suis bon, et ce serait dommage De priver l\'univers d\'un homme de courage. Demande-moi pardon, et cesse par tes feux De profaner l\'objet digne seul de mes vœux ; Tu connais ma valeur, éprouve ma clémence.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Plutôt, si votre amour a tant de véhémence, Faisons deux coups d\'épée au nom de sa beauté.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Parbleu, tu me ravis de générosité. Va, pour la conquérir n\'use plus d\'artifices, Je te la veux donner pour prix de tes services ; Plains-toi dorénavant d\'avoir un maître ingrat !' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'À ce rare présent, d\'aise le cœur me bat. Protecteur des grands rois, guerrier trop magnanime, Puisse tout l\'univers bruire de votre estime !' },
    { k: 'scene', t: 'Scène X' },
    { k: 'didascalie', t: '(ISABELLE, MATAMORE, CLINDOR.)' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je rends grâces au ciel de ce qu\'il a permis Qu\'à la fin, sans combat, je vous vois bons amis.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Ne pensez plus, ma reine, à l\'honneur que ma flamme Vous devait faire un jour de vous prendre pour femme ; Pour quelque occasion j\'ai changé de dessein : Mais je vous veux donner un homme de ma main ; Faites-en de l\'état ; il est vaillant lui-même ; Il commandait sous moi.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Pour vous plaire, je l\'aime.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Mais il faut du silence à notre affection.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Je vous promets silence, et ma protection. Avouez-vous de moi par tous les coins du monde. Je suis craint à l\'égal sur la terre et sur l\'onde ; Allez, vivez contents sous une même loi.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Pour vous mieux obéir je lui donne ma foi.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Commandez que sa foi de quelque effet suivie…' },
    { k: 'scene', t: 'Scène XI' },
    { k: 'didascalie', t: '(GÉRONTE, ADRASTE, MATAMORE, CLINDOR, ISABELLE, LYSE, TROUPE DE DOMESTIQUES)' },
    { k: 'perso', t: 'ADRASTE' },
    { k: 'ligne', t: 'Cet insolent discours te coûtera la vie, Suborneur.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Ils ont pris mon courage en défaut. Cette porte est ouverte, allons gagner le haut.' },
    { k: 'didascalie', t: '(Il entre chez Isabelle après qu\'elle et Lyse y sont entrées.)' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Traître ! qui te fais fort d\'une troupe brigande, Je te choisirai bien au milieu de la bande.' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'Dieux ! Adraste est blessé, courez au médecin. Vous autres, cependant, arrêtez l\'assassin.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Ah, ciel ! je cède au nombre. Adieu, chère Isabelle ; Je tombe au précipice où mon destin m\'appelle.' },
    { k: 'perso', t: 'GÉRONTE' },
    { k: 'ligne', t: 'C\'en est fait, emportez ce corps à la maison ; Et vous, conduisez tôt ce traître à la prison.' },
    { k: 'scene', t: 'Scène XII' },
    { k: 'didascalie', t: '(ALCANDRE, PRIDAMANT.)' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Hélas ! mon fils est mort.' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Que vous avez d\'alarmes !' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Ne lui refusez point le secours de vos charmes.' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Un peu de patience, et, sans un tel secours, Vous le verrez bientôt heureux en ses amours. Acte quatrième' },
    { k: 'scene', t: 'Scène I' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Enfin le terme approche ; un jugement inique Doit abuser demain d\'un pouvoir tyrannique, A son propre assassin immoler mon amant, Et faire une vengeance au lieu d\'un châtiment. Par un décret injuste autant comme sévère, Demain doit triompher la haine de mon père, La faveur du pays, la qualité du mort, Le malheur d\'Isabelle, et la rigueur du sort. Hélas ! que d\'ennemis, et de quelle puissance, Contre le faible appui que donne l\'innocence, Contre un pauvre inconnu, de qui tout le forfait Est de m\'avoir aimée, et d\'être trop parfait ! Oui, Clindor, tes vertus et ton feu légitime, T\'ayant acquis mon cœur, ont fait aussi ton crime. Mais en vain après toi l\'on me laisse le jour ; Je veux perdre la vie en perdant mon amour : Prononçant ton arrêt, c\'est de moi qu\'on dispose ; Je veux suivre ta mort, puisque j\'en suis la cause, Et le même moment verra par deux trépas Nos esprits amoureux se rejoindre là-bas. Ainsi, père inhumain, ta cruauté déçue De nos saintes ardeurs verra l\'heureuse issue ; Et si ma perte alors fait naître tes douleurs, Auprès de mon amant je rirai de tes pleurs. Ce qu\'un remords cuisant te coûtera de larmes D\'un si doux entretien augmentera les charmes ; Ou s\'il n\'a pas assez de quoi te tourmenter, Mon ombre chaque jour viendra t\'épouvanter, S\'attacher à tes pas dans l\'horreur des ténèbres, Présenter à tes yeux mille images funèbres, Jeter dans ton esprit un éternel effroi, Te reprocher ma mort, t\'appeler après moi, Accabler de malheurs ta languissante vie, Et te réduire au point de me porter envie. Enfin…' },
    { k: 'scene', t: 'Scène II' },
    { k: 'didascalie', t: '(ISABELLE, LYSE.)' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Quoi ! chacun dort, et vous êtes ici ? Je vous jure, monsieur en est en grand souci.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Quand on n\'a plus d\'espoir, Lyse, on n\'a plus de crainte. Je trouve des douceurs à faire ici ma plainte. Ici je vis Clindor pour la dernière fois ; Ce lieu me redit mieux les accents de sa voix, Et remet plus avant en mon âme éperdue L\'aimable souvenir d\'une si chère vue.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Que vous prenez de peine à grossir vos ennuis !' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Que veux-tu que je fasse en l\'état où je suis ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'De deux amants parfaits dont vous étiez servie, L\'un doit mourir demain, l\'autre est déjà sans vie : Sans perdre plus de temps à soupirer pour eux, Il en faut trouver un qui les vaille tous deux.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'De quel front oses-tu me tenir ces paroles ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Quel fruit espérez-vous de vos douleurs frivoles ? Pensez-vous, pour pleurer et tenir vos appas, Rappeler votre amant des portes du trépas ? Songez plutôt à faire une illustre conquête ; Je sais pour vos liens une âme toute prête, Un homme incomparable.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Ote-toi de mes yeux.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Le meilleur jugement ne choisirait pas mieux.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Pour croître mes douleurs faut-il que je te voie ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Et faut-il qu\'à vos yeux je déguise ma joie ?' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'D\'où te vient cette joie ainsi hors de saison ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Quand je vous l\'aurai dit, jugez si j\'ai raison.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Ah ! ne me conte rien.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Mais l\'affaire vous touche.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Parle-moi de Clindor, ou n\'ouvre point la bouche.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Ma belle humeur, qui rit au milieu des malheurs, Fait plus en un moment qu\'un siècle de vos pleurs ; Elle a sauvé Clindor.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Sauvé Clindor ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Lui-même : Jugez après cela comme quoi je vous aime.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Eh ! de grâce, où faut-il que je l\'aille trouver ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Je n\'ai que commencé, c\'est à vous d\'achever.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Ah ! Lyse !' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Tout de bon, seriez-vous pour le suivre ?' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Si je suivrais celui sans qui je ne puis vivre ? Lyse, si ton esprit ne le tire des fers, Je l\'accompagnerai jusque dans les enfers. Va, ne demande plus si je suivrais sa fuite.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Puisqu\'à ce beau dessein l\'amour vous a réduite, Écoutez où j\'en suis, et secondez mes coups ; Si votre amant n\'échappe, il ne tiendra qu\'à vous. La prison est tout proche.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Eh bien ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Ce voisinage Au frère du concierge a fait voir mon visage ; Et comme c\'est tout un que me voir et m\'aimer, Le pauvre malheureux s\'en est laissé charmer.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je n\'en avais rien su !' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'J\'en avais tant de honte Que je mourais de peur qu\'on vous en fît le conte ; Mais depuis quatre jours votre amant arrêté A fait que l\'allant voir je l\'ai mieux écouté. Des yeux et du discours flattant son espérance, D\'un mutuel amour j\'ai formé l\'apparence. Quand on aime une fois, et qu\'on se croit aimé, On fait tout pour l\'objet dont on est enflammé. Par là j\'ai sur son âme assuré mon empire, Et l\'ai mis en état de ne m\'oser dédire. Quand il n\'a plus douté de mon affection, J\'ai fondé mes refus sur sa condition ; Et lui, pour m\'obliger, jurait de s\'y déplaire, Mais que malaisément il s\'en pouvait défaire ; Que les clefs des prisons qu\'il gardait aujourd\'hui Étaient le plus grand bien de son frère et de lui. Moi de dire soudain que sa bonne fortune Ne lui pouvait offrir d\'heure plus opportune ; Que, pour se faire riche, et pour me posséder, Il n\'avait seulement qu\'à s\'en accommoder ; Qu\'il tenait dans les fers un seigneur de Bretagne Déguisé sous le nom du sieur de la Montagne ; Qu\'il fallait le sauver, et le suivre chez lui ; Qu\'il nous ferait du bien, et serait notre appui. Il demeure étonné ; je le presse, il s\'excuse ; Il me parle d\'amour, et moi je le refuse ; Je le quitte en colère ; il me suit tout confus, Me fait nouvelle excuse, et moi nouveau refus.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Mais enfin ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'J\'y retourne, et le trouve fort triste ; Je le juge ébranlé ; je l\'attaque, il résiste. Ce matin : "En un mot, le péril est pressant", Ai-je dit ; "tu peux tout, et ton frère est absent." "Mais il faut de l\'argent pour un si long voyage," M\'a-t-il dit ; "il en faut pour faire l\'équipage ; "Ce cavalier en manque."' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Ah, Lyse ! tu devais Lui faire offre aussitôt de tout ce que j\'avais, Perles, bagues, habits.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'J\'ai bien fait davantage, J\'ai dit qu\'à vos beautés ce captif rend hommage. Que vous l\'aimez de même, et fuirez avec nous. Ce mot me l\'a rendu si traitable et si doux, Que j\'ai bien reconnu qu\'un peu de jalousie Touchant votre Clindor brouillait sa fantaisie, Et que tous ces détours provenaient seulement D\'une vaine frayeur qu\'il ne fût mon amant. Il est parti soudain après votre amour sue, A trouvé tout aisé, m\'en a promis l\'issue, Et vous mande par moi qu\'environ à minuit Vous soyez toute prête à déloger sans bruit.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Que tu me rends heureuse !' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Ajoutez-y, de grâce, Qu\'accepter un mari pour qui je suis de glace, C\'est me sacrifier à vos contentements.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Aussi…' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Je ne veux point de vos remerciements. Allez ployer bagage ; et pour grossir la somme, Joignez à vos bijoux les écus du bon homme. Je vous vends ses trésors, mais à fort bon marché ; J\'ai dérobé ses clefs depuis qu\'il est couché ; Je vous les livre.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Allons y travailler ensemble.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Passez-vous de mon aide.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Eh quoi ! le cœur te tremble ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Non, mais c\'est un secret tout propre à l\'éveiller ; Nous ne nous garderions jamais de babiller.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Folle, tu ris toujours.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'De peur d\'une surprise, Je dois attendre ici le chef de l\'entreprise ; S\'il tardait à la rue, il serait reconnu ; Nous vous irons trouver dès qu\'il sera venu. C\'est là sans raillerie…' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Adieu donc. Je te laisse, Et consens que tu sois aujourd\'hui la maîtresse.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'C\'est du moins…' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Fais bon guet.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Vous, faites bon butin.' },
    { k: 'scene', t: 'Scène III' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Ainsi, Clindor, je fais moi seule ton destin ; Des fers où je t\'ai mis c\'est moi qui te délivre, Et te puis, à mon choix, faire mourir ou vivre. On me vengeait de toi par-delà mes désirs ; Je n\'avais de dessein que contre tes plaisirs. Ton sort trop rigoureux m\'a fait changer d\'envie ; Je te veux assurer tes plaisirs et ta vie ; Et mon amour éteint, te voyant en danger, Renaît pour m\'avertir que c\'est trop me venger. J\'espère aussi, Clindor, que, pour reconnaissance, De ton ingrat amour étouffant la licence…' },
    { k: 'scene', t: 'Scène IV' },
    { k: 'didascalie', t: '(MATAMORE, ISABELLE, LYSE.)' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Quoi ! chez nous, et de nuit !' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'L\'autre jour…' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Qu\'est ceci, L\'autre jour ? est-il temps que je vous trouve ici ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'C\'est ce grand capitaine. Où s\'est-il laissé prendre ?' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'En montant l\'escalier je l\'en ai vu descendre.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'L\'autre jour, au défaut de mon affection, J\'assurai vos appas de ma protection.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Après ?' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'On vint ici faire une brouillerie ; Vous rentrâtes voyant cette forfanterie ; Et, pour vous protéger, je vous suivis soudain.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Votre valeur prit lors un généreux dessein. Depuis ?' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Pour conserver une dame si belle, Au plus haut du logis j\'ai fait la sentinelle.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Sans sortir ?' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Sans sortir.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'C\'est-à-dire, en deux mots, Que la peur l\'enfermait dans la chambre aux fagots.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'La peur ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Oui, vous tremblez ; la vôtre est sans égale.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Parce qu\'elle a bon pas, j\'en fais mon Bucéphale ; Lorsque je la domptai, je lui fis cette loi ; Et depuis, quand je marche, elle tremble sous moi.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Votre caprice est rare à choisir des montures.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'C\'est pour aller plus vite aux grandes aventures.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Vous en exploitez bien : mais changeons de discours Vous avez demeuré là-dedans quatre jours ?' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Quatre jours.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Et vécu ?' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'De nectar, d\'ambrosie.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Je crois que cette viande aisément rassasie ?' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Aucunement.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Enfin vous étiez descendu…' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Pour faire qu\'un amant en vos bras fût rendu, Pour rompre sa prison, en fracasser les portes, Et briser en morceaux ses chaînes les plus fortes.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Avouez franchement que, pressé par la faim, Vous veniez bien plutôt faire la guerre au pain.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'L\'un et l\'autre, parbieu. Cette ambrosie est fade, J\'en eus au bout d\'un jour l\'estomac tout malade. C\'est un mets délicat, et de peu de soutien ; À moins que d\'être un dieu l\'on n\'en vivrait pas bien ; Il cause mille maux, et dès l\'heure qu\'il entre, Il allonge les dents, et rétrécit le ventre.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Enfin c\'est un ragoût qui ne vous plaisait pas ?' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Quitte pour chaque nuit faire deux tours en bas, Et là, m\'accommodant des reliefs de cuisine, Mêler la viande humaine avecque la divine.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Vous aviez, après tout, dessein de nous voler.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Vous-mêmes, après tout, m\'osez-vous quereller ? Si je laisse une fois échapper ma colère…' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Lyse, fais-moi sortir les valets de mon père.' },
    { k: 'perso', t: 'MATAMORE' },
    { k: 'ligne', t: 'Un sot les attendrait.' },
    { k: 'scene', t: 'Scène V' },
    { k: 'didascalie', t: '(ISABEL, LYSE.)' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Vous ne le tenez pas.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Il nous avait bien dit que la peur a bon pas.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Vous n\'avez cependant rien fait, ou peu de chose.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Rien du tout. Que veux-tu ? sa rencontre en est cause.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Mais vous n\'aviez alors qu\'à le laisser aller.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Mais il m\'a reconnue, et m\'est venu parler. Moi qui, seule et de nuit, craignais son insolence, Et beaucoup plus encor de troubler le silence, J\'ai cru, pour m\'en défaire et m\'ôter de souci, Que le meilleur était de l\'amener ici. Vois quand j\'ai ton secours, que je me tiens vaillante, Puisque j\'ose affronter cette humeur violente.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'J\'en ai ri comme vous, mais non sans murmurer : C\'est bien du temps perdu.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je vais le réparer.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Voici le conducteur de notre intelligence ; Sachez auparavant toute sa diligence.' },
    { k: 'scene', t: 'Scène VI' },
    { k: 'didascalie', t: '(ISABELLE, LYSE, LE GEÔLIER.)' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Eh bien ! mon grand ami, braverons-nous le sort ? Et viens-tu m\'apporter ou la vie ou la mort ? Ce n\'est plus qu\'en toi seul que mon espoir se fonde.' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'Bannissez vos frayeurs, tout va le mieux du monde ; Il ne faut que partir, j\'ai des chevaux tout prêts, Et vous pourrez bientôt vous moquer des arrêts.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je te dois regarder comme un dieu tutélaire, Et ne sais point pour toi d\'assez digne salaire.' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'Voici le prix unique où tout mon cœur prétend.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Lyse, il faut te résoudre à le rendre content.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Oui, mais tout son apprêt nous est fort inutile ; Comment ouvrirons-nous les portes de la ville ?' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'On nous tient des chevaux en main sûre aux faubourgs ; Et je sais un vieux mur qui tombe tous les jours : Nous pourrons aisément sortir par ses ruines.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Ah ! que je me trouvais sur d\'étranges épines !' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'Mais il faut se hâter.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Nous partirons soudain. Viens nous aider là-haut à faire notre main.' },
    { k: 'scene', t: 'Scène VII' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'didascalie', t: '(en prison)' },
    { k: 'ligne', t: 'Aimables souvenirs de mes chères délices, Qu\'on va bientôt changer en d\'infâmes supplices, Que, malgré les horreurs de ce mortel effroi, Vos charmants entretiens ont de douceurs pour moi ! Ne m\'abandonnez point, soyez-moi plus fidèles Que les rigueurs du sort ne se montrent cruelles ; Et lorsque du trépas les plus noires couleurs Viendront à mon esprit figurer mes malheurs, Figurez aussitôt à mon âme interdite Combien je fus heureux par delà mon mérite Lorsque je me plaindrai de leur sévérité, Redites-moi l\'excès de ma témérité ; Que d\'un si haut dessein ma fortune incapable Rendait ma flamme injuste, et mon espoir coupable ; Que je fus criminel quand je devins amant, Et que ma mort en est le juste châtiment. Quel bonheur m\'accompagne à la fin de ma vie ! Isabelle, je meurs pour vous avoir servie ; Et de quelque tranchant que je souffre les coups, Je meurs trop glorieux, puisque je meurs pour vous. Hélas ! que je me flatte, et que j\'ai d\'artifice À me dissimuler la honte d\'un supplice ! En est-il de plus grand que de quitter ces yeux Dont le fatal amour me rend si glorieux ? L\'ombre d\'un meurtrier creuse ici ma ruine ; Il succomba vivant, et mort, il m\'assassine ; Son nom fait contre moi ce que n\'a pu son bras ; Mille assassins nouveaux naissent de son trépas ; Et je vois de son sang, fécond en perfidies, S\'élever contre moi des âmes plus hardies, De qui les passions, s\'armant d\'autorité, Font un meurtre public avec impunité. Demain de mon courage on doit faire un grand crime, Donner au déloyal ma tête pour victime ; Et tous pour le pays prennent tant d\'intérêt, Qu\'il ne m\'est pas permis de douter de l\'arrêt. Ainsi de tous côtés ma perte était certaine. J\'ai repoussé la mort, je la reçois pour peine. D\'un péril évité je tombe en un nouveau, Et des mains d\'un rival en celles d\'un bourreau. Je frémis à penser à ma triste aventure ; Dans le sein du repos je suis à la torture ; Au milieu de la nuit, et du temps du sommeil, Je vois de mon trépas le honteux appareil ; J\'en ai devant les yeux les funestes ministres ; On me lit du sénat les mandements sinistres ; Je sors les fers aux pieds ; j\'entends déjà le bruit De l\'amas insolent d\'un peuple qui me suit ; Je vois le lieu fatal où ma mort se prépare : Là mon esprit se trouble, et ma raison s\'égare ; Je ne découvre rien qui m\'ose secourir, Et la peur de la mort me fait déjà mourir. Isabelle, toi seule, en réveillant ma flamme, Dissipes ces terreurs et rassures mon âme ; Et sitôt que je pense à tes divins attraits, Je vois évanouir ces infâmes portraits. Quelques rudes assauts que le malheur me livre, Garde mon souvenir, et je croirai revivre. Mais d\'où vient que de nuit on ouvre ma prison ? Ami, que viens-tu faire ici hors de saison ?' },
    { k: 'scene', t: 'Scène VIII' },
    { k: 'didascalie', t: '(CLINDOR, LE GEÔLIER)' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'didascalie', t: '(cependant qu\'Isabelle et Lyse paraissent à quartier.)' },
    { k: 'ligne', t: 'Les juges assemblés pour punir votre audace, Mus de compassion, enfin vous ont fait grâce.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'M\'ont fait grâce, bons dieux !' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'Oui, vous mourrez de nuit.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'De leur compassion est-ce là tout le fruit ?' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'Que de cette faveur, vous tenez peu de compte ! D\'un supplice public c\'est vous sauver la honte.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Quels encens puis-je offrir aux maîtres de mon sort, Dont l\'arrêt me fait grâce, et m\'envoie à la mort ?' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'Il la faut recevoir avec meilleur visage.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Fais ton office, ami, sans causer davantage. LE' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'Une troupe d\'archers là-dehors vous attend ; Peut-être en les voyant serez-vous plus content.' },
    { k: 'scene', t: 'Scène IX' },
    { k: 'didascalie', t: '(CLINDOR, ISABELLE, LYSE, LE GEÔLIER)' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'didascalie', t: '(dit ces mots à Lyse, cependant que le geôlier ouvre la prison à Clindor.)' },
    { k: 'ligne', t: 'Lyse, nous l\'allons voir.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Que vous êtes ravie !' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Ne le serais-je point de recevoir la vie ? Son destin et le mien prennent un même cours, Et je mourrais du coup qui trancherait ses jours.' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'Monsieur, connaissez-vous beaucoup d\'archers semblables ?' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Ah ! madame, est-ce vous ? surprises adorables ! Trompeur trop obligeant ! tu disais bien vraiment Que je mourrais de nuit, mais de contentement.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Clindor !' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'Ne perdons point de temps à ces caresses. Nous aurons tout loisir de flatter nos maîtresses.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Quoi ! Lyse est donc la sienne ?' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Écoutez le discours De votre liberté qu\'ont produit leurs amours.' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'En lieu de sûreté le babil est de mise, Mais ici ne songeons qu\'à nous ôter de prise.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Sauvons-nous : mais avant, promettez-nous tous deux Jusqu\'au jour d\'un hymen de modérer vos feux : Autrement, nous rentrons.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Que cela ne vous tienne, Je vous donne ma foi.' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'Lyse, reçois la mienne.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Sur un gage si beau j\'ose tout hasarder.' },
    { k: 'perso', t: 'LE GEÔLIER' },
    { k: 'ligne', t: 'Nous nous amusons trop, il est temps d\'évader.' },
    { k: 'scene', t: 'Scène X' },
    { k: 'didascalie', t: '(ALCANDRE, PRIDAMANT.)' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Ne craignez plus pour eux ni périls ni disgrâces ! Beaucoup les poursuivront, mais sans trouver leurs traces.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'À la fin je respire.' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Après un tel bonheur, Deux ans les ont montés en haut degré d\'honneur. Je ne vous dirai point le cours de leurs voyages, S\'ils ont trouvé le calme, ou vaincu les orages, Ni par quel art non plus ils se sont élevés ; Il suffit d\'avoir vu comme ils se sont sauvés, Et que, sans vous en faire une histoire importune, Je vous les vais montrer en leur haute fortune. Mais puisqu\'il faut passer à des effets plus beaux, Rentrons pour évoquer des fantômes nouveaux ! Ceux que vous avez vus représenter de suite À vos yeux étonnés leur amour et leur fuite, N\'étant pas destinés aux hautes fonctions, N\'ont point assez d\'éclat pour leurs conditions. Acte cinquième' },
    { k: 'scene', t: 'Scène I' },
    { k: 'didascalie', t: '(ALCANDRE, PRIDAMANT.)' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Qu\'Isabelle est changée et qu\'elle est éclatante !' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Lyse marche après elle, et lui sert de suivante ; Mais derechef surtout n\'ayez aucun effroi, Et de ce lieu fatal ne sortez qu\'après moi ; Je vous le dis encore, il y va de la vie.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Cette condition m\'en ôte assez l\'envie.' },
    { k: 'scene', t: 'Scène II' },
    { k: 'didascalie', t: '(ISABELLE, REPRÉSENTANT HIPPOLYTE; LYSE, REPRÉSENTANT CLARINE.)' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Ce divertissement n\'aura-t-il point de fin ? Et voulez-vous passer la nuit dans ce jardin ?' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je ne puis plus cacher le sujet qui m\'amène ; C\'est grossir mes douleurs que de taire ma peine. Le prince Florilame…' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Eh bien, il est absent.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'C\'est la source des maux que mon âme ressent ; Nous sommes ses voisins, et l\'amour qu\'il nous porte Dedans son grand jardin nous permet cette porte. La princesse Rosine, et mon perfide époux, Durant qu\'il est absent, en font leur rendez-vous : Je l\'attends au passage, et lui ferai connaître Que je ne suis pas femme à rien souffrir d\'un traître.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Madame, croyez-moi, loin de le quereller, Vous ferez beaucoup mieux de tout dissimuler. Il nous vient peu de fruit de telles jalousies ; Un homme en court plus tôt après ses fantaisies ; Il est toujours le maître, et tout notre discours, Par un contraire effet l\'obstine en ses amours.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je dissimulerai son adultère flamme ! Une autre aura son cœur, et moi le nom de femme ! Sans crime, d\'un hymen peut-il rompre la loi ? Et ne rougit-il point d\'avoir si peu de foi ?' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Cela fut bon jadis ; mais au temps où nous sommes, Ni l\'hymen ni la foi n\'obligent plus les hommes ; Leur gloire a son brillant et ses règles à part ; Où la nôtre se perd, la leur est sans hasard ; Elle croît aux dépens de nos lâches faiblesses ; L\'honneur d\'un galant homme est d\'avoir des maîtresses.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Ôte-moi cet honneur et cette vanité, De se mettre en crédit par l\'infidélité. Si, pour haïr le change et vivre sans amie, Un homme tel que lui tombe dans l\'infamie, Je le tiens glorieux d\'être infâme à ce prix ; S\'il en est méprisé, j\'estime ce mépris. Le blâme qu\'on reçoit d\'aimer trop une femme Aux maris vertueux est un illustre blâme.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Madame, il vient d\'entrer ; la porte a fait du bruit.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Retirons-nous, qu\'il passe.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Il vous voit et vous suit.' },
    { k: 'scene', t: 'Scène III' },
    { k: 'didascalie', t: '(CLINDOR, REPRÉSENTANT THÉAGÈNE; ISABELLE, REPRÉSENTANT HIPPOLYTE; LYSE, REPRÉSENTANT CLARINE.)' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Vous fuyez, ma princesse, et cherchez des remises : Sont-ce là les douceurs que vous m\'aviez promises ? Est-ce ainsi que l\'amour ménage un entretien ? Ne fuyez plus, madame, et n\'appréhendez rien : Florilame est absent, ma jalouse endormie.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'En êtes-vous bien sûr ?' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Ah ! fortune ennemie !' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je veille, déloyal : ne crois plus m\'aveugler ; Au milieu de la nuit je ne vois que trop clair ; Je vois tous mes soupçons passer en certitudes, Et ne puis plus douter de tes ingratitudes ! Toi-même, par ta bouche, as trahi ton secret. Ô l\'esprit avisé pour un amant discret ! Et que c\'est en amour une haute prudence D\'en faire avec sa femme entière confidence ! Où sont tant de serments de n\'aimer rien que moi ? Qu\'as-tu fait de ton cœur ? qu\'as-tu fait de ta foi ? Lorsque je la reçus, ingrat, qu\'il te souvienne De combien différaient ta fortune et la mienne, De combien de rivaux je dédaignai les vœux, Ce qu\'un simple soldat pouvait être auprès d\'eux ; Quelle tendre amitié je recevais d\'un père ! Je le quittai pourtant pour suivre ta misère ; Et je tendis les bras à mon enlèvement, Pour soustraire ma main à son commandement. En quelle extrémité depuis ne m\'ont réduite Les hasards dont le sort a traversé ta fuite ? Et que n\'ai-je souffert avant que le bonheur Élevât ta bassesse à ce haut rang d\'honneur ! Si, pour te voir heureux, ta foi s\'est relâchée, Remets-moi dans le sein dont tu m\'as arrachée. L\'amour que j\'ai pour toi m\'a fait tout hasarder, Non pas pour des grandeurs, mais pour te posséder.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Ne me reproche plus ta fuite ni ta flamme. Que ne fait point l\'amour quand il possède une âme ? Son pouvoir à ma vue attachait tes plaisirs, Et tu me suivais moins que tes propres désirs. J\'étais lors peu de chose, oui ; mais qu\'il te souvienne Que ta fuite égala ta fortune à la mienne, Et que pour t\'enlever c\'était un faible appas Que l\'éclat de tes biens qui ne te suivaient pas. Je n\'eus, de mon côté, que l\'épée en partage, Et ta flamme, du tien, fut mon seul avantage : Celle-là m\'a fait grand en ces bords étrangers, L\'autre exposa ma tête à cent et cent dangers. Regrette maintenant ton père et ses richesses ; Fâche-toi de marcher à côté des princesses ; Retourne en ton pays chercher avec tes biens L\'honneur d\'un rang pareil à celui que tu tiens. De quel manque, après tout, as-tu lieu de te plaindre ? En quelle occasion m\'as-tu vu te contraindre ? As-tu reçu de moi ni froideurs, ni mépris ? Les femmes, à vrai dire, ont d\'étranges esprits ! Qu\'un mari les adore, et qu\'un amour extrême À leur bizarre humeur le soumette lui-même, Qu\'il les comble d\'honneurs et de bons traitements, Qu\'il ne refuse rien à leurs contentements : S\'il fait la moindre brèche à la foi conjugale, Il n\'est point à leur gré de crime qui l\'égale ; C\'est vol, c\'est perfidie, assassinat, poison, C\'est massacrer son père, et brûler sa maison : Et jadis des Titans l\'effroyable supplice Tomba sur Encelade avec moins de justice.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je te l\'ai déjà dit, que toute ta grandeur Ne fut jamais l\'objet de ma sincère ardeur. Je ne suivais que toi, quand je quittai mon père ; Mais puisque ces grandeurs t\'ont fait l\'âme légère, Laisse mon intérêt ; songe à qui tu les dois. Florilame lui seul t\'a mis où tu te vois ; À peine il te connut qu\'il te tira de peine ; De soldat vagabond il te fit capitaine ; Et le rare bonheur qui suivit cet emploi Joignit à ses faveurs les faveurs de son roi. Quelle forte amitié n\'a-t-il point fait paraître À cultiver depuis ce qu\'il avait fait naître ? Par ses soins redoublés n\'es-tu pas aujourd\'hui Un peu moindre de rang, mais plus puissant que lui ? Il eût gagné par là l\'esprit le plus farouche ; Et pour remerciement tu veux souiller sa couche ! Dans ta brutalité trouve quelques raisons, Et contre ses faveurs défends tes trahisons. Il t\'a comblé de biens, tu lui voles son âme ! Il t\'a fait grand seigneur, et tu le rends infâme ! Ingrat, c\'est donc ainsi que tu rends les bienfaits ? Et ta reconnaissance a produit ces effets ?' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Mon âme car encor ce beau nom te demeure, Et te demeurera jusqu\'à tant que je meure, Crois-tu qu\'aucun respect ou crainte du trépas Puisse obtenir sur moi ce que tu n\'obtiens pas ? Dis que je suis ingrat, appelle-moi parjure ; Mais à nos feux sacrés ne fais plus tant d\'injure : Ils conservent encor leur première vigueur ; Et si le fol amour qui m\'a surpris le cœur Avait pu s\'étouffer au point de sa naissance, Celui que je te porte eût eu cette puissance. Mais en vain mon devoir tâche à lui résister ; Toi-même as éprouvé qu\'on ne le peut dompter. Ce dieu qui te força d\'abandonner ton père, Ton pays et tes biens, pour suivre ma misère, Ce dieu même aujourd\'hui force tous mes désirs À te faire un larcin de deux ou trois soupirs. À mon égarement souffre cette échappée, Sans craindre que ta place en demeure usurpée. L\'amour dont la vertu n\'est point le fondement Se détruit de soi-même, et passe en un moment ; Mais celui qui nous joint est un amour solide, Où l\'honneur a son lustre, où la vertu préside ; Sa durée a toujours quelques nouveaux appas, Et ses fermes liens durent jusqu\'au trépas. Mon âme, derechef pardonne à la surprise Que ce tyran des cœurs a faite à ma franchise ; Souffre une folle ardeur qui ne vivra qu\'un jour, Et qui n\'affaiblit point le conjugal amour.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Hélas ! que j\'aime bien à m\'abuser moi-même ! Je vois qu\'on me trahit, et veux croire qu\'on m\'aime ; Je me laisse charmer à ce discours flatteur, Et j\'excuse un forfait dont j\'adore l\'auteur. Pardonne, cher époux, au peu de retenue Où d\'un premier transport la chaleur est venue : C\'est en ces accidents manquer d\'affection Que de les voir sans trouble et sans émotion. Puisque mon teint se fane et ma beauté se passe, Il est bien juste aussi que ton amour se lasse ; Et même je croirai que ce feu passager En l\'amour conjugal ne pourra rien changer. Songe un peu toutefois à qui ce feu s\'adresse, En quel péril te jette une telle maîtresse. Dissimule, déguise, et sois amant discret. Les grands en leur amour n\'ont jamais de secret ; Ce grand train qu\'à leurs pas leur grandeur propre attache N\'est qu\'un grand corps tout d\'yeux à qui rien ne se cache, Et dont il n\'est pas un qui ne fît son effort À se mettre en faveur par un mauvais rapport. Tôt ou tard Florilame apprendra tes pratiques, Ou de sa défiance, ou de ses domestiques ; Et lors' },
    { k: 'didascalie', t: '(à ce penser je frissonne d\'horreur)' },
    { k: 'ligne', t: 'À quelle extrémité n\'ira point sa fureur ? Puisqu\'à ces passe-temps ton humeur te convie, Cours après tes plaisirs, mais assure ta vie. Sans aucun sentiment je te verrai changer, Lorsque tu changeras sans te mettre en danger.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Encore une fois donc tu veux que je te die Qu\'auprès de mon amour je méprise ma vie ? Mon âme est trop atteinte, et mon cœur trop blessé, Pour craindre les périls dont je suis menacé. Ma passion m\'aveugle, et pour cette conquête C\'est hasarder trop peu de hasarder ma tête. C\'est un feu que le temps pourra seul modérer ; C\'est un torrent qui passe et ne saurait durer.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Eh bien, cours au trépas, puisqu\'il a tant de charmes Et néglige ta vie aussi bien que mes larmes. Penses-tu que ce prince, après un tel forfait, Par ta punition se tienne satisfait ? Qui sera mon appui lorsque ta mort infâme À sa juste vengeance exposera ta femme, Et que sur la moitié d\'un perfide étranger Une seconde fois il croira se venger ? Non, je n\'attendrai pas que ta perte certaine Puisse attirer sur moi les restes de ta peine, Et que de mon honneur, gardé si chèrement, Il fasse un sacrifice à son ressentiment. Je préviendrai la honte où ton malheur me livre, Et saurai bien mourir, si tu ne veux pas vivre. Ce corps, dont mon amour t\'a fait le possesseur, Ne craindra plus bientôt l\'effort d\'un ravisseur. J\'ai vécu pour t\'aimer, mais non pour l\'infamie De servir au mari de ton illustre amie. Adieu ; je vais du moins, en mourant avant toi, Diminuer ton crime, et dégager ta foi.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Ne meurs pas, chère épouse, et dans un second change Vois l\'effet merveilleux où ta vertu me range. M\'aimer malgré mon crime, et vouloir par ta mort Éviter le hasard de quelque indigne effort ! Je ne sais qui je dois admirer davantage, Ou de ce grand amour, ou de ce grand courage ; Tous les deux m\'ont vaincu : je reviens sous tes lois, Et ma brutale ardeur va rendre les abois ; C\'en est fait, elle expire, et mon âme plus saine Vient de rompre les nœuds de sa honteuse chaîne. Mon cœur, quand il fut pris, s\'était mal défendu ; Perds-en le souvenir.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Je l\'ai déjà perdu.' },
    { k: 'perso', t: 'CLINDOR' },
    { k: 'ligne', t: 'Que les plus beaux objets qui soient dessus la terre Conspirent désormais à me faire la guerre ; Ce cœur, inexpugnable aux assauts de leurs yeux N\'aura plus que les tiens pour maîtres et pour dieux.' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Madame, quelqu\'un vient.' },
    { k: 'scene', t: 'Scène IV' },
    { k: 'didascalie', t: '(CLINDOR, REPRÉSENTANT THÉAGÈNE; ISABELLE, REPRÉSENTANT HIPPOLYTE; LYSE, REPRÉSENTANT CLARINE; ÉRASTE;TROUPE DE DOMESTIQUES DE FLORILAME)' },
    { k: 'perso', t: 'ÉRASTE' },
    { k: 'didascalie', t: '(poignardant Clindor.)' },
    { k: 'ligne', t: 'Reçois, traître, avec joie Les faveurs que par nous ta maîtresse t\'envoie.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'didascalie', t: '(à Alcandre.)' },
    { k: 'ligne', t: 'On l\'assassine, ô dieux ! daignez le secourir.' },
    { k: 'perso', t: 'ÉRASTE' },
    { k: 'ligne', t: 'Puissent les suborneurs ainsi toujours périr !' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Qu\'avez-vous fait, bourreaux ?' },
    { k: 'perso', t: 'ÉRASTE' },
    { k: 'ligne', t: 'Un juste et grand exemple, Qu\'il faut qu\'avec effroi tout l\'avenir contemple, Pour apprendre aux ingrats, aux dépens de son sang, A n\'attaquer jamais l\'honneur d\'un si haut rang. Notre main a vengé le prince Florilame, La princesse outragée, et vous-même, madame, Immolant à tous trois un déloyal époux, Qui ne méritait pas la gloire d\'être à vous. D\'un si lâche attentat souffrez le prompt supplice, Et ne vous plaignez point quand on vous rend justice. Adieu.' },
    { k: 'perso', t: 'ISABELLE' },
    { k: 'ligne', t: 'Vous ne l\'avez massacré qu\'à demi, Il vit encore en moi ; soûlez son ennemi : Achevez, assassins, de m\'arracher la vie. Cher époux, en mes bras on te l\'a donc ravie ! Et de mon cœur jaloux les secrets mouvements N\'ont pu rompre ce coup par leurs pressentiments ! O clarté trop fidèle, hélas ! et trop tardive, Qui ne fait voir le mal qu\'au moment qu\'il arrive ! Fallait-il… Mais j\'étouffe, et, dans un tel malheur, Mes forces et ma voix cèdent à ma douleur ; Son vif excès me tue ensemble et me console, Et puisqu\'il nous rejoint…' },
    { k: 'perso', t: 'LYSE' },
    { k: 'ligne', t: 'Elle perd la parole. Madame… Elle se meurt ; épargnons les discours, Et courons au logis appeler du secours.' },
    { k: 'didascalie', t: '(Ici on rabaisse une toile qui couvre le jardin et les corps de Clindor et d\'Isabelle, et le magicien et le père sortent de la grotte.)' },
    { k: 'scene', t: 'Scène V' },
    { k: 'didascalie', t: '(ALCANDRE, PRIDAMANT.)' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Ainsi de notre espoir la fortune se joue : Tout s\'élève ou s\'abaisse au branle de sa roue : Et son ordre inégal, qui régit l\'univers, Au milieu du bonheur a ses plus grands revers.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Cette réflexion, mal propre pour un père, Consolerait peut-être une douleur légère ; Mais, après avoir vu mon fils assassiné, Mes plaisirs foudroyés, mon espoir ruiné, J\'aurais d\'un si grand coup l\'âme bien peu blessée, Si de pareils discours m\'entraient dans la pensée. Hélas ! dans sa misère il ne pouvait périr ; Et son bonheur fatal lui seul l\'a fait mourir. N\'attendez pas de moi des plaintes davantage : La douleur qui se plaint cherche qu\'on la soulage ; La mienne court après son déplorable sort. Adieu ; je vais mourir, puisque mon fils est mort.' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'D\'un juste désespoir l\'effort est légitime, Et de le détourner je croirais faire un crime. Oui, suivez ce cher fils sans attendre à demain ; Mais épargnez du moins ce coup à votre main ; Laissez faire aux douleurs qui rongent vos entrailles, Et pour les redoubler voyez ses funérailles.' },
    { k: 'didascalie', t: '(Ici on relève la toile, et tous les comédiens paraissent avec leur portier, qui comptent de l\'argent sur une table, et en prennent chacun leur part.)' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Que vois-je ? chez les morts compte-t-on de l\'argent ?' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Voyez si pas un d\'eux s\'y montre négligent.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Je vois Clindor ! ah dieux ! quelle étrange surprise ! Je vois ses assassins, je vois sa femme et Lyse ! Quel charme en un moment étouffe leurs discords, Pour assembler ainsi les vivants et les morts ?' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Ainsi tous les acteurs d\'une troupe comique, Leur poème récité, partagent leur pratique : L\'un tue, et l\'autre meurt, l\'autre vous fait pitié ; Mais la scène préside à leur inimitié. Leurs vers font leurs combats, leur mort suit leurs paroles, Et, sans prendre intérêt en pas un de leurs rôles, Le traître et le trahi, le mort et le vivant, Se trouvent à la fin amis comme devant. Votre fils et son train ont bien su, par leur fuite, D\'un père et d\'un prévôt éviter la poursuite ; Mais tombant dans les mains de la nécessité, Ils ont pris le théâtre en cette extrémité.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Mon fils comédien !' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'D\'un art si difficile Tous les quatre, au besoin, ont fait un doux asile ; Et, depuis sa prison, ce que vous avez vu, Son adultère amour, son trépas imprévu, N\'est que la triste fin d\'une pièce tragique Qu\'il expose aujourd\'hui sur la scène publique, Par où ses compagnons en ce noble métier Ravissent à Paris un peuple tout entier. Le gain leur en demeure, et ce grand équipage, Dont je vous ai fait voir le superbe étalage, Est bien à votre fils, mais non pour s\'en parer Qu\'alors que sur la scène il se fait admirer.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'J\'ai pris sa mort pour vraie, et ce n\'était que feinte ; Mais je trouve partout même sujet de plainte. Est-ce là cette gloire, et ce haut rang d\'honneur Où le devait monter l\'excès de son bonheur ?' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Cessez de vous en plaindre. À présent le théâtre Est en un point si haut que chacun l\'idolâtre ; Et ce que votre temps voyait avec mépris Est aujourd\'hui l\'amour de tous les bons esprits, L\'entretien de Paris, le souhait des provinces, Le divertissement le plus doux de nos princes, Les délices du peuple, et le plaisir des grands ; Il tient le premier rang parmi leurs passe-temps ; Et ceux dont nous voyons la sagesse profonde Par ses illustres soins conserver tout le monde, Trouvent dans les douceurs d\'un spectacle si beau De quoi se délasser d\'un si pesant fardeau. Même notre grand roi, ce foudre de la guerre Dont le nom se fait craindre aux deux bouts de la terre, Le front ceint de lauriers, daigne bien quelquefois Prêter l\'œil et l\'oreille au Théâtre-François : C\'est là que le Parnasse étale ses merveilles ; Les plus rares esprits lui consacrent leurs veilles ; Et tous ceux qu\'Apollon voit d\'un meilleur regard De leurs doctes travaux lui donnent quelque part. D\'ailleurs, si par les biens on prise les personnes, Le théâtre est un fief dont les rentes sont bonnes ; Et votre fils rencontre en un métier si doux Plus d\'accommodement qu\'il n\'eût trouvé chez vous. Défaites-vous enfin de cette erreur commune, Et ne vous plaignez plus de sa bonne fortune.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Je n\'ose plus m\'en plaindre, et vois trop de combien Le métier qu\'il a pris est meilleur que le mien. Il est vrai que d\'abord mon âme s\'est émue : J\'ai cru la comédie au point où je l\'ai vue ; J\'en ignorais l\'éclat, l\'utilité, l\'appas, Et la blâmais ainsi, ne la connaissant pas ; Mais, depuis vos discours, mon cœur plein d\'allégresse A banni cette erreur avecque sa tristesse. Clindor a trop bien fait.' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'N\'en croyez que vos yeux.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Demain, pour ce sujet, j\'abandonne ces lieux ; Je vole vers Paris. Cependant, grand Alcandre, Quelles grâces ici ne vous dois-je point rendre ?' },
    { k: 'perso', t: 'ALCANDRE' },
    { k: 'ligne', t: 'Servir les gens d\'honneur est mon plus grand désir. J\'ai pris ma récompense en vous faisant plaisir. Adieu. Je suis content, puisque je vous vois l\'être.' },
    { k: 'perso', t: 'PRIDAMANT' },
    { k: 'ligne', t: 'Un si rare bienfait ne se peut reconnaître : Mais, grand mage, du moins croyez qu\'à l\'avenir Mon âme en gardera l\'éternel souvenir.' },
    { k: 'didascalie', t: '(FIN)' },
  ],
};

